"</style></head><body style=\" font-family:\'Segoe UI\'; font-size:9pt; font-weight:400; font-style:normal;\" bgcolor=\"#1e1e2e\">\n"
"<p style=\" margin-top:0px; margin-bottom:16px; margin-left:0px; margin-right:0px; -qt-block-indent:0; text-indent:0px; background-color:#1e1e1e;\"><span style=\" font-family:\'Segoe UI\',\'Arial\',\'sans-serif\'; font-size:14pt; font-weight:700; color:#90caf9;\">📏 Espaçamento dos Estribos </span><span style=\" font-family:\'Segoe UI\',\'Arial\',\'sans-serif\'; font-size:10pt; color:#b0bec5;\">NBR 6118:2023 – Item 18.3.4.1 </span></p>\n"
"<p style=\" margin-top:0px; margin-bottom:10px; margin-left:0px; margin-right:0px; -qt-block-indent:0; text-indent:0px; background-color:#252525;\"><span style=\" font-family:\'Segoe UI\',\'Arial\',\'sans-serif\'; font-size:12pt; color:#b0bec5; background-color:#252525;\">Dados de Entrada </span></p>\n"
