"<p style=\" margin-top:0px; margin-bottom:0px; margin-left:0px; margin-right:0px; -qt-block-indent:0; text-indent:0px;\"><span style=\" font-family:\'Segoe UI\',\'Arial\',\'sans-serif\'; color:#b0bec5;\">A</span><span style=\" font-family:\'Segoe UI\',\'Arial\',\'sans-serif\'; color:#b0bec5; vertical-align:sub;\">sw</span><span style=\" font-family:\'Segoe UI\',\'Arial\',\'sans-serif\'; color:#b0bec5;\">/s necessário</span></p></td>\n"
"<td style=\" padding-left:0; padding-right:0; padding-top:4; padding-bottom:4;\">\n"
